const express = require('express');
const axios = require('axios');

const app = express();
const port = 3000;

app.use(express.json());

// In-memory cache for NIN verification results
const ninCache = new Map();

app.post('/api/verify-nin', async (req, res) => {
  const { nin } = req.body;

  if (!nin) {
    return res.status(400).json({ error: 'NIN is required' });
  }

  // Check cache
  if (ninCache.has(nin)) {
    console.log(`Cache hit for NIN: ${nin}`);
    return res.json(ninCache.get(nin));
  }

  try {
    const response = await axios.post(
      'https://api.prembly.com/verification/nin',
      { number: nin },
      {
        headers: {
          'app-id': process.env.PREMBLY_APP_ID,
          'x-api-key': process.env.PREMBLY_API_KEY,
          'Content-Type': 'application/json'
        }
      }
    );

    // Cache the successful response data
    ninCache.set(nin, response.data);
    console.log(`Cache miss for NIN: ${nin}. Data cached.`);

    return res.json(response.data);
  } catch (error) {
    console.error('Error verifying NIN:', error.response ? error.response.data : error.message);

    const status = error.response ? error.response.status : 500;
    const message = error.response ? error.response.data : { error: 'Internal Server Error' };

    return res.status(status).json(message);
  }
});

app.listen(port, () => {
  console.log(`Server listening on port ${port}`);
});

